                            }
                            else if (Status == "Reject")
                            {
                                dbsrs.LoiLists.Remove(checkloi);
                                dbsrs.SaveChanges();
                            }
                        }
                    }
                    else if (Type == "LOILISTUPDATE")
                    {
                        var checkloi = dbsrs.LoiLists.Where(aa => aa.Refnumber == Reqid).SingleOrDefault();
                        if (checkloi != null)
                        {
                            checkloi.Status = Status;
                            dbsrs.SaveChanges();
                        }
                    }
                }
                catch
                {
                }
            }
            return View();
        }
