        public string DecryptUsingCertificate(string data, string password)
        {
            byte[] byteData = Convert.FromBase64String(data);
            string pathchk = System.Web.Hosting.HostingEnvironment.MapPath("~/");
            string path = pathchk + "CERT/mycertprivatekey.pfx";
            var Password = password;
            var collection = new X509Certificate2Collection();
            collection.Import(System.IO.File.ReadAllBytes(path), Password, X509KeyStorageFlags.PersistKeySet | X509KeyStorageFlags.MachineKeySet | X509KeyStorageFlags.PersistKeySet);
            X509Certificate2 certificate = new X509Certificate2();
            certificate = collection[0];
            foreach (var cert in collection)
            {
                if (cert.FriendlyName.Contains("my certificate"))
                {
                    certificate = cert;
                }
            }
            if (certificate.HasPrivateKey)
            {
                var privateKey = certificate.PrivateKey as RSACryptoServiceProvider;
                return Encoding.UTF8.GetString(privateKey.Decrypt(byteData, false));
            }
            return null;
        }

        [HttpPost]
        public ActionResult CashfreeResponse()
        {
            var websitename = "";
            using (VastwebmultiEntities dbsrs = new VastwebmultiEntities())
            {
                websitename = dbsrs.Admin_details.SingleOrDefault().WebsiteUrl;
                try
                {
                    string content = "";
                    System.Web.HttpContext.Current.Request.InputStream.Position = 0;
                    using (var reader = new StreamReader(Request.InputStream, Encoding.UTF8, true, 4096, true))
                    {
                        content = reader.ReadToEnd();
                    }
                    WriteLogCASHFREE("***********************************UPI*******************************************", websitename);
                    WriteLogCASHFREE("Time :" + DateTime.Now, websitename);
                    WriteLogCASHFREE("CASHFREE :" + content, websitename);

                    dynamic respdata = JsonConvert.DeserializeObject(content);
                    string status = respdata.data?.payment?.payment_status;
                    string custid = respdata.data?.order?.order_id;
                    string amt = respdata.data?.payment?.payment_amount;
                    string cf_payment_id = respdata.data?.payment?.cf_payment_id;
                    string BankRRN = respdata.data?.payment?.bank_reference;
                    string upi_id = respdata.data?.payment?.payment_method?.upi?.upi_id;
                    string customer_details = respdata.data?.customer_details?.customer_name;

                    //string status = Request.QueryString["txStatus"];// respdata.data?.payment?.payment_status;
                    //string custid = Request.QueryString["orderId"];// respdata.data?.order?.order_id;
                    //string amt = Request.QueryString["orderAmount"]; //respdata.data?.payment?.payment_amount;
                    //string cf_payment_id = Request.QueryString["orderId"]; //respdata.data?.payment?.cf_payment_id;
                    //string BankRRN = Request.QueryString["referenceId"]; //respdata.data?.payment?.bank_reference;
                    //string upi_id = Request.QueryString["orderId"]; //respdata.data?.payment?.payment_method?.upi?.upi_id;
                    //string customer_details = Request.QueryString["txMsg"];  //respdata.data?.customer_details?.customer_name;

                    var exitsup = dbsrs.Upi_txn_details.Where(a => a.BankRRN == BankRRN).SingleOrDefault();
                    if (exitsup == null)
                    {
                        decimal amount = Convert.ToDecimal(amt);
                        var count = dbsrs.cashfreepayments.Where(aa => aa.custid == custid).FirstOrDefault();
                        if (count != null)
                        {
                            System.Data.Entity.Core.Objects.ObjectParameter output = new
                                  System.Data.Entity.Core.Objects.ObjectParameter("Output", typeof(string));

                            //var chkinfo=dbsrs.upi
                            dbsrs.UPI_TXN("Retailer", count.userid, cf_payment_id, amount, status, customer_details, upi_id, BankRRN, content, "CASHFREE", output).SingleOrDefault();
                            try
                            {
                                var retailerdetails = dbsrs.Retailer_Details.Where(aa => aa.RetailerId == count.userid).SingleOrDefault();
                                var dealerdetails = dbsrs.Dealer_Details.Where(aa => aa.DealerId == retailerdetails.DealerId).SingleOrDefault();
                                var masterdetails = dbsrs.Superstokist_details.Where(aa => aa.SSId == dealerdetails.SSId).SingleOrDefault();

                                var remdetails = dbsrs.Remain_reteller_balance.Where(aa => aa.RetellerId == count.userid).SingleOrDefault();
                                var dlmdetails = dbsrs.Remain_dealer_balance.Where(aa => aa.DealerID == retailerdetails.DealerId).SingleOrDefault();
                                var Masterdetails = dbsrs.Remain_superstokist_balance.Where(aa => aa.SuperStokistID == dealerdetails.SSId).SingleOrDefault();

                                var admininfo = dbsrs.Admin_details.SingleOrDefault();
                                Backupinfo back = new Backupinfo();

                                var model = new Backupinfo.Addinfo
                                {

                                    Websitename = admininfo.WebsiteUrl,
                                    RetailerID = count.userid,
                                    Email = retailerdetails.Email,
                                    Mobile = retailerdetails.Mobile,
                                    Details = "UPI Fund Transfer",
                                    RemainBalance = (decimal)remdetails.Remainamount,
                                    Usertype = "Retailer"
                                };
                                back.Rechargeandutility(model);

                            }
                            catch { }
                            var retailer = dbsrs.Retailer_Details.Where(aa => aa.RetailerId == count.userid).SingleOrDefault();
                            var newremain = dbsrs.Remain_reteller_balance.Where(aa => aa.RetellerId == count.userid).SingleOrDefault().Remainamount.ToString();
                            var AdminDetails = dbsrs.Admin_details.SingleOrDefault();

                            try
                            {
                                if (status.ToUpper().Contains("SUCCESS"))
                                {
                                    smssend.sms_init("Y", "Y", "UPITRANSFERSUCCESSFULLY", retailer.Mobile, amount, newremain);

                                    smssend.SendEmailAll(retailer.Email, "UPI Transfer Rs." + amount + " Successfull .New Balance is " + newremain + "", "UPI TRANSFER", AdminDetails.email);

                                }
                                else if ((status.ToUpper().Contains("FAILED")) || status.ToUpper().Contains("FAILURE"))
                                {
                                    smssend.sms_init("Y", "Y", "UPITRANSFERFAILED", retailer.Mobile, amount, newremain);

                                    smssend.SendEmailAll(retailer.Email, "UPI Transfer Rs." + amount + " Failed .New Balance is " + newremain + "", "UPI TRANSFER", AdminDetails.email);
                                }
                            }
                            catch { }
                        }
                    }
                    var resp = new
                    {
                        Status = "Hit SuccessFully",
                    };
                    return Json(resp, JsonRequestBehavior.AllowGet);

                }
                catch (Exception ex)
                {
                    WriteLogCASHFREE("CASHFREE Catch Error :" + ex.Message, websitename);
                    var resp = new
                    {
                        Status = "Hit SuccessFully with Exception",
                    };
                    return Json(resp, JsonRequestBehavior.AllowGet);
                }
            }

        }

