        [HttpGet]
        public string securityipsts()
        {
            string resp = "Hit Successfully";
            try
            {
                using (VastwebmultiEntities dbsrs = new VastwebmultiEntities())
                {
                    var token = string.Empty;
                    token = getAuthToken();
                    string ipaddress = "";
                    ipaddress = Request.UserHostAddress;
                    var moneytoken = dbsrs.Money_API_URLS.Where(a => a.API_Name == "VASTWEB").SingleOrDefault().Token;
                    if (ipaddress == "::1")
                    {
                        ipaddress = new WebClient().DownloadString("http://ipv4.icanhazip.com/");
                        ipaddress = ipaddress.Replace("\n", "");
                    }
                    WriteLogIP("Time :" + DateTime.Now);
                    WriteLogIP("ipaddress :" + ipaddress);

                    System.Net.ServicePointManager.SecurityProtocol = SecurityProtocolType.Tls12;
                    var client = new RestClient("http://api.vastbazaar.com/api/Web/IPCHECK");
                    client.Timeout = -1;
                    var request = new RestRequest(Method.POST);
                    request.AddHeader("Authorization", "Bearer " + token);
                    request.AddHeader("Content-Type", "application/json");

                    var body = new
                    {
                        token = moneytoken,
                        ipaddress = ipaddress
                    };
                    var bodystring = JsonConvert.SerializeObject(body);

                    request.AddParameter("application/json", bodystring, ParameterType.RequestBody);
                    IRestResponse response = client.Execute(request);
                    if (response.StatusCode.ToString() == "OK")
                    {
                        dynamic respdata = JsonConvert.DeserializeObject<dynamic>(response.Content);
                        WriteLogIP("Respponse :" + respdata);

                        if (respdata.Content.ADDINFO.status == true)
                        {
                            var ipexistornot = dbsrs.ipadreesvalidates.ToList();
                            if (ipexistornot.Count() > 0)
                            {
                                foreach (var item in ipexistornot)
                                {
                                    item.ipstatus = "N";

                                }
                                dbsrs.SaveChanges();
                                resp = respdata.msg;
                            }
                        }
                        else
                        {
                            resp = respdata.msg;
                        }
                    }
                    else
                    {
                        resp = "Something went wrong";
                    }

                }
            }
            catch (Exception ex)
            {
                resp = ex.Message;
                return resp;
            }

            return resp;

        }
        public ActionResult UpdateInstantPay()
        {
            using (VastwebmultiEntities dbsrs = new VastwebmultiEntities())
            {
                var ipay_id = Request.QueryString["ipay_id"];
                var agent_id = Request.QueryString["agent_id"];
                var opr_id = Request.QueryString["opr_id"];
                var status = Request.QueryString["status"];
                var res_code = Request.QueryString["res_code"];
                var res_msg = Request.QueryString["res_msg"];
                var outpt = HttpContext.Request.Url.AbsoluteUri;
                test1 objCourse = new test1();
                objCourse.name = outpt;
                dbsrs.test1.Add(objCourse);
                dbsrs.SaveChanges();
                try
                {
                    var entry = (from rch in dbsrs.Recharge_info
                                 where rch.Order_id == agent_id
                                 && rch.Rstaus.ToUpper().Contains("REQ")
                                 select new
                                 {
                                     Idno = rch.idno,
                                     userid = rch.Rch_from,
                                     Mobile = rch.Mobile,
                                     Port = rch.portno,
                                     Amount = rch.amount,
                                     Provider = rch.optcode,
                                     Response = rch.response_output,
                                     rch_type=rch.rch_type

                                 }).SingleOrDefault();
                    var IMPS_entry = (from rch in dbsrs.IMPS_transtion_detsils
                                      where rch.trans_id == agent_id
                                      && rch.Status.ToUpper().Contains("PEN")
                                      select new
                                      {
                                          Idno = rch.idno,
                                          UserID = rch.rch_from,
                                          SenderNUMBER = rch.senderno,
                                          Amount = rch.amount,
                                          TransactionID = rch.trans_id,
                                          //NewTransactionID = rch.trans_id,
                                          AccountNo = rch.accountno,
                                          IFSC = rch.ifsccode,
                                          Mode = rch.Trans_Type,
                                          Response = rch.Response_output

                                      }).SingleOrDefault();
                    if (entry != null)
                    {
                        if (res_code.ToUpper() == "TXN")
                        {
                            status = "SUCCESS";
                            dbsrs.recharge_update(entry.Idno.ToString(), status, opr_id, Convert.ToDecimal(entry.Amount), outpt, "ResponseOutput");
                        }
                        else if (res_code.ToUpper() == "TUP")
                        {
                            //  var hh = "Pending";
                        }
                        else
                        {
                            status = "FAILED";
                            dbsrs.recharge_update(entry.Idno.ToString(), status, opr_id, Convert.ToDecimal(entry.Amount), outpt, "ResponseOutput");
                            if (entry.rch_type == "API")
                            {
                                try
                                {
                                    var retailerdetails = dbsrs.api_user_details.Where(aa => aa.apiid == entry.userid).SingleOrDefault();
                                    var remdetails = dbsrs.api_remain_amount.Where(aa => aa.apiid == entry.userid).SingleOrDefault();

                                    var admininfo = dbsrs.Admin_details.SingleOrDefault();
                                    Backupinfo back = new Backupinfo();
