        public ActionResult mRobotics()
        {
            using (VastwebmultiEntities dbsrs = new VastwebmultiEntities())
            {
                try
                {
                    var ipcheck = dbsrs.api_name.Where(a => a.api_url.ToUpper().Contains("MROBOTICS.IN")).SingleOrDefault().ipaddress;
                    string ipaddress = "";
                    ipaddress = GetComputer_InternetIP();
                    if (ipaddress == "::1")
                    {
                        ipaddress = new WebClient().DownloadString("http://ipv4.icanhazip.com/");
                        ipaddress = ipaddress.Replace("\n", "");
                    }
                    if (!String.IsNullOrWhiteSpace(ipcheck))
                    {
                        if (ipcheck == ipaddress)
                        { }
                        else
                        {
                            return View();
                        }
                    }
                }
                catch
                { }

                var lapubal = Request.Form["balance"];
                var status = Request.Form["status"];
                var rchid = Request.Form["order_id"];
                var operatorid = Request.Form["tnx_id"];

                var Params = Request.Form;
                var outpt = HttpContext.Request.Url.AbsoluteUri + " : Params :" + Params;

                test1 objCourse = new test1();
                objCourse.name = outpt;
                dbsrs.test1.Add(objCourse);
                dbsrs.SaveChanges();
                try
                {
                    var entry = (from rch in dbsrs.Recharge_info
                                 where rch.Order_id == rchid
                                 select new
                                 {
                                     Idno = rch.idno,
                                     Mobile = rch.Mobile,
                                     Port = rch.portno,
                                     Amount = rch.amount,
                                     Provider = rch.optcode,
                                     Response = rch.Recharge_response,
                                     userid = rch.Rch_from,
                                     CurrentStatus = rch.Rstaus,
                                     OrderId = rch.Order_id

