        public ActionResult RechargeServices()
        {
            using (VastwebmultiEntities dbsrs = new VastwebmultiEntities())
            {

                var rchid = Request.QueryString["refid"];
                var status = Request.QueryString["status"];
                var operatorid = Request.QueryString["opid"];
                var lapubal = Request.QueryString["remainbalance"];
                if (lapubal == "" || lapubal == null)
                {
                    lapubal = "0";
                }

                var comm = Request.QueryString["comm"];
                if (comm == "" || comm == null)
                {
                    comm = "0";
                }

                var outpt = HttpContext.Request.Url.AbsoluteUri;

                test1 objCourse = new test1();
                objCourse.name = outpt;
