                    //var encryptedPaymentId =   form["encryptedPaymentId"].ToString();
                    var bank_ref_num = form["bank_ref_num"].ToString();
                    //var key =   form["key"].ToString();
                    //var email =   form["email"].ToString();
                    var amount = form["amount"].ToString();
                    //var unmappedstatus =   form["unmappedstatus"].ToString();
                    //var address2 =   form["address2"].ToString();
                    var payuMoneyId = "";
                    try
                    {
                        payuMoneyId = form["payuMoneyId"].ToString();
                    }
                    catch
                    {
                        payuMoneyId = form["mihpayid"].ToString();
                    }



                    //var address1 =   form["address1"].ToString();
                    //var udf5 =   form["udf5"].ToString();

                    //var udf6 =   form["udf6"].ToString();
                    //var udf3 =   form["udf3"].ToString();
                    //var udf4 =   form["udf4"].ToString();
                    //var udf1 =   form["udf1"].ToString();
                    //var udf2 =   form["udf2"].ToString();
                    //var giftCardIssued =   form["giftCardIssued"].ToString();
                    //var field1 =   form["field1"].ToString();
                    //var cardnum =   form["cardnum"].ToString();
                    //var field7 =   form["field7"].ToString();
                    //var field6 =   form["field6"].ToString();
                    //var field9 =   form["field9"].ToString();
                    //var field8 =   form["field8"].ToString();
                    //var amount_split =   form["amount_split"].ToString();
                    //var field3 =   form["field3"].ToString();
                    //var field2 =   form["field2"].ToString();
                    //var field5 =   form["field5"].ToString();
                    var PG_TYPE = form["PG_TYPE"].ToString();
                    //var field4 =   form["field4"].ToString();
                    //var name_on_card =   form["name_on_card"].ToString();



                    var token = string.Empty;
                    token = getAuthToken();
                    var charge = "0";
                    var recive = "0";

                    if (mode.ToUpper() == "NB" || mode.ToUpper() == "DC")
                    {
                        if (status.ToUpper() == "SUCCESS")
                        {
                            try
                            {
                                var gatewayinfo = dbsrs.Gateway_Auth.SingleOrDefault();
                                var command = "verify_payment";
                                string hashString = gatewayinfo.merchantkey + "|" + command + "|" + txnid + "|" + gatewayinfo.merchantsalt;
                                string hashchk = Generatehash512(hashString);
                                var client = new RestClient("https://info.payu.in/merchant/postservice.php?form=2");
                                client.Timeout = -1;
                                var request = new RestRequest(Method.POST);
                                request.AddHeader("Content-Type", "application/x-www-form-urlencoded");
                                request.AddParameter("key", gatewayinfo.merchantkey);
                                request.AddParameter("command", "verify_payment");
                                request.AddParameter("var1", txnid);
                                request.AddParameter("hash", hashchk);
                                IRestResponse response = client.Execute(request);
                                WriteLoggateway("Status Response " + response.Content, websitename.WebsiteUrl);
                                dynamic resp = JsonConvert.DeserializeObject(response.Content);
                                bankcode = resp.transaction_details[txnid].bankcode.ToString();
                            }
                            catch { }
                        }
                    }
                    try
                    {
                        var firmname = ""; var useremail = ""; var usermobile = "";
                        var paymentinfo = dbsrs.Payment_Gateway_Txn_history.Where(aa => aa.txnid == txnid).SingleOrDefault();
                        if (paymentinfo.roles.ToUpper() == "RETAILER")
                        {
                            var reminfo = dbsrs.Retailer_Details.Where(aa => aa.RetailerId == paymentinfo.userid).SingleOrDefault();
                            firmname = reminfo.Frm_Name;
                            useremail = reminfo.Email;
                            usermobile = reminfo.Mobile;
                        }
                        else if (paymentinfo.roles.ToUpper() == "DEALER")
                        {
                            var reminfo = dbsrs.Dealer_Details.Where(aa => aa.DealerId == paymentinfo.userid).SingleOrDefault();
                            firmname = reminfo.FarmName;
                            useremail = reminfo.Email;
                            usermobile = reminfo.Mobile;
                        }
                        else if (paymentinfo.roles.ToUpper() == "API")
                        {
                            var reminfo = dbsrs.api_user_details.Where(aa => aa.apiid == paymentinfo.userid).SingleOrDefault();
                            firmname = reminfo.farmname;
                            useremail = reminfo.emailid;
                            usermobile = reminfo.mobile;
                        }
                        else if (paymentinfo.roles.ToUpper() == "MASTER")
                        {
                            var reminfo = dbsrs.Superstokist_details.Where(aa => aa.SSId == paymentinfo.userid).SingleOrDefault();
                            firmname = reminfo.FarmName;
                            useremail = reminfo.Email;
                            usermobile = reminfo.Mobile;
                        }
                        var client = new RestClient("http://api.vastbazaar.com/api/Web/Netbanking");
                        client.Timeout = -1;
                        var request = new RestRequest(Method.POST);
                        request.AddHeader("Authorization", "Bearer " + token);
                        request.AddHeader("Content-Type", "application/json");
                        var body = new
                        {
                            usertype = paymentinfo.roles,
                            useremail = useremail,
                            userfirmname = firmname,
                            usermobile = usermobile,
                            txndate = DateTime.Now,
                            txnid = txnid,
                            mode = mode,
                            bankcode = bankcode,
                            status = status,
                            bank_ref_num = bank_ref_num,
                            error_Message = error_Message,
                            payuMoneyId = payuMoneyId,
                            PG_TYPE = PG_TYPE,
                            amount = amount
                        };
                        var reqchk = JsonConvert.SerializeObject(body);
                        request.AddParameter("application/json", reqchk, ParameterType.RequestBody);
                        IRestResponse response = client.Execute(request);
                    }
                    catch { }



                    var websiteurl = dbsrs.Admin_details.SingleOrDefault().WebsiteUrl;
                    WriteLoggateway("MSG " + websiteurl + ",,,,,,,,, " + mode + "-" + status + "-" + txnid + "-" + amount + "-" + PG_TYPE + "-" + bank_ref_num + "-" + bankcode + "-" + error_Message + "-" + payuMoneyId, websitename.WebsiteUrl);
                    System.Data.Entity.Core.Objects.ObjectParameter output = new
                    System.Data.Entity.Core.Objects.ObjectParameter("Output", typeof(string));
                    dbsrs.PaymentGateway_Fund(txnid, mode, bankcode, status, bank_ref_num, error_Message, "", "", payuMoneyId, PG_TYPE, output);
                    var info = dbsrs.Payment_Gateway_Txn_history.Where(aa => aa.txnid == txnid).SingleOrDefault();
                    charge = info.charge.ToString();
                    recive = info.totalpay.ToString();

                    var modechk = "";
                    if (mode.ToUpper() == "CC")
                    {
                        modechk = "Credit Card";
                    }
                    else if (mode.ToUpper() == "DC")
                    {
                        modechk = "Debit Card";
                    }
                    else if (mode.ToUpper() == "NB")
                    {
                        modechk = "Net Banking";
                    }
                    else if (mode.ToUpper() == "CASH")
                    {
                        modechk = "Wallet";
                    }
                    else if (mode.ToUpper() == "UPI")
                    {
                        modechk = "UPI";
                    }
                    ViewBag.Status = status.ToUpper();
                    ViewBag.amount = amount;
                    ViewBag.Mode = modechk;
                    ViewBag.type = bankcode;
                    ViewBag.payid = payuMoneyId;
                    if (status.ToUpper() == "SUCCESS")
                    {
                        ViewBag.bankrrn = bank_ref_num;
                    }
                    else
                    {
                        ViewBag.bankrrn = error_Message;
                    }
                    ViewBag.charge = charge;
                    ViewBag.recive = recive;
                    ViewBag.time = DateTime.Now.ToString("dddd, dd MMMM yyyy HH:mm:ss");
                }
                catch (Exception ex)
                {
                }
            }
            return View();
        }

