        public ActionResult VastWebAutoUPIFund(string amount, string bankrrn, string payeename, string status, string txnid, DateTime renewal, string type)
        {
            using (VastwebmultiEntities dbsrs = new VastwebmultiEntities())
            {
                if (type == "WEBSITE")
                {
                    VastWeb_upi_txn_deatils txn = new VastWeb_upi_txn_deatils();
                    txn.amount = Convert.ToDecimal(amount);
                    txn.bankrrn = bankrrn;
                    txn.ndate = DateTime.Now;
                    txn.payeename = payeename;
                    txn.status = status;
                    txn.txnid = txnid;
                    dbsrs.VastWeb_upi_txn_deatils.Add(txn);
                    Admin_details admin = new Admin_details();
                    admin.RenivalDate = renewal;
                    dbsrs.SaveChanges();
                }

            }
            return View();
        }
        public string Generatehash512(string text)
        {
            byte[] message = Encoding.UTF8.GetBytes(text);
            UnicodeEncoding UE = new UnicodeEncoding();
            byte[] hashValue;
            SHA512Managed hashString = new SHA512Managed();
            string hex = "";
            hashValue = hashString.ComputeHash(message);
            foreach (byte x in hashValue)
            {
                hex += String.Format("{0:x2}", x);
            }
            return hex;
        }
        public static void WriteLoggateway(string strMessage, string websitename)
        {
            try
            {
                StreamWriter log;
                FileStream fileStream = null;
                DirectoryInfo logDirInfo = null;
                FileInfo logFileInfo;
                string logFilePath = "C:\\Logs\\";
                logFilePath = logFilePath + " PAYMENTGATEWAY " + websitename + " - " + System.DateTime.Today.ToString("MM-dd-yyyy") + "." + "txt";
                logFileInfo = new FileInfo(logFilePath);
                logDirInfo = new DirectoryInfo(logFileInfo.DirectoryName);
                if (!logDirInfo.Exists) logDirInfo.Create();
                if (!logFileInfo.Exists)
                {
                    fileStream = logFileInfo.Create();
                }
                else
                {
                    fileStream = new FileStream(logFilePath, FileMode.Append);
                }
                log = new StreamWriter(fileStream);
                log.WriteLine(strMessage);
                log.Close();
            }
            catch (Exception ex)
            {
            }
        }
        public static void WriteLogUPI(string strMessage, string name)
