        public string getAuthToken()
        {
            try
            {
                using (VastwebmultiEntities dbsrs = new VastwebmultiEntities())
                {
                    var tokn = dbsrs.vastbazzartokens.SingleOrDefault();
                    if (tokn == null)
                    {
                        var response = tokencheck();
                        var responsechk = response.Content.ToString();
                        var responsecode = response.StatusCode.ToString();
                        if (responsecode == "OK")
                        {
                            Vastbillpay vb = new Vastbillpay();
                            dynamic json = JsonConvert.DeserializeObject(responsechk);
                            var token = json.access_token.ToString();
                            var expire = json[".expires"].ToString();
                            DateTime exp = Convert.ToDateTime(expire);
                            vastbazzartoken vast = new vastbazzartoken();
                            vast.apitoken = token;
                            vast.exptime = exp;
                            dbsrs.vastbazzartokens.Add(vast);
                            dbsrs.SaveChanges();
                            return tokn.apitoken;
                        }
                        else
                        {
                            return null;
                        }
                    }
                    else
                    {
                        DateTime curntdate = DateTime.Now.Date;
                        DateTime expdate = Convert.ToDateTime(tokn.exptime).Date;
                        if (expdate > curntdate)
                        {
                            return tokn.apitoken;
                        }
                        else
                        {
                            var response = tokencheck();
                            var responsechk = response.Content.ToString();
                            var responsecode = response.StatusCode.ToString();
                            if (responsecode == "OK")
                            {

                                dynamic json = JsonConvert.DeserializeObject(responsechk);
                                var token = json.access_token.ToString();
                                var expire = json[".expires"].ToString();
                                DateTime exp = Convert.ToDateTime(expire);

                                tokn.apitoken = token;
                                tokn.exptime = exp;
                                dbsrs.SaveChanges();
                                return token;
                            }
                            else
                            {
                                return null;
                            }
                        }

                    }
                }
            }
            catch
            {
                return null;
            }
        }
        public IRestResponse tokencheck()
        {
            using (VastwebmultiEntities dbsrs = new VastwebmultiEntities())
            {
                var apidetails = dbsrs.Money_API_URLS.Where(aa => aa.API_Name == "VASTWEB").SingleOrDefault();
                var token = apidetails == null ? "" : apidetails.Token;
                var apiid = apidetails == null ? "" : apidetails.API_ID;
                var apiidpwd = apidetails == null ? "" : apidetails.Api_pwd;
                var client = new RestClient("http://api.vastbazaar.com/token");
                var request = new RestRequest(Method.POST);
                request.AddHeader("iptoken", token);
                request.AddHeader("content-type", "application/x-www-form-urlencoded");
                request.AddParameter("application/x-www-form-urlencoded", "UserName=" + apiid + "&Password=" + apiidpwd + "&grant_type=password", ParameterType.RequestBody);
                IRestResponse response = client.Execute(request);
                return response;
            }
        }

        public async Task<string> SendNotificationUsingTopic()
        {
            AppNotification aa = new AppNotification();
            string str = "";
            str += await aa.SendNotificationUsingTopic("vastweb", "test title", "vastweb");
            str += await aa.SendNotificationUsingTopic("vastweb-retailer", "test title", "vastweb-retailer");
            str += await aa.SendNotificationUsingTopic("vastweb-dealer", "test title", "vastweb-dealer");
            str += await aa.SendNotificationUsingTopic("vastweb-master", "test title", "vastweb-master");
            return str;
        }
        
        public  string test(string lat,string longitude)
        {
            decimal latlong = 0;
            decimal longlong = 0;
            try
            {
                 latlong = Convert.ToDecimal(lat);
                 longlong = Convert.ToDecimal(longitude);
            }
            catch { }
            if (IsValidLatitudeLongitude(latlong, longlong) == false)
            {
                var result = GenerateRandomLocationInIndia();
                lat = result.Item1.ToString();
                longitude = result.Item2.ToString();
            }
            return "";
        }
        private static readonly Random _random = new Random();
        private static Tuple<double, double> GenerateRandomLocationInIndia()
        {
            double minLat = 8.0;   // South (Kanyakumari)
            double maxLat = 37.0;  // North (Jammu & Kashmir)
            double minLon = 68.0;  // West (Gujarat)
            double maxLon = 97.0;  // East (Arunachal Pradesh)

            double randomLat = minLat + (_random.NextDouble() * (maxLat - minLat));
            double randomLon = minLon + (_random.NextDouble() * (maxLon - minLon));

            return System.Tuple.Create(randomLat, randomLon);
        }
        public void insertGeoLocation(string userid, out string lat, out string longitude)
        {
            lat = string.Empty;
            longitude = string.Empty;
            System.Net.ServicePointManager.SecurityProtocol = SecurityProtocolType.Tls11|SecurityProtocolType.Tls12;
            var client = new RestClient("https://ipinfo.io");
